        left = 0
        ans = 0

        # For each right, only need to inspect suffixes of lengths up to max_len (<= 10).
        for right in range(n):
            for L, patterns in forb_by_len.items():
                start = right - L + 1
                if start < left:
                    continue
                if start >= 0:
                    sub = word[start:right + 1]
                    if sub in patterns:
                        # If a forbidden substring ends at right, the valid window must start after it.
                        left = start + 1
            ans = max(ans, right - left + 1)

