from typing import List

class Solution:
    def longestValidSubstring(self, word: str, forbidden: List[str]) -> int:
        # Build a set of forbidden substrings for O(1) membership checks
        forb = set(forbidden)
        max_len = 0
        for f in forbidden:
            if len(f) > max_len:
                max_len = len(f)

        n = len(word)
        left = 0  # left boundary of the current valid window
        ans = 0

        # Sliding window with limited backward checks (max forbidden length <= 10)
        for r in range(n):
            # If any forbidden substring ends at r, move left past its start
            # We only need to check substrings of lengths 1..max_len ending at r.
            for L in range(1, max_len + 1):
                if r - L + 1 < left:
                    break  # earlier starts are already excluded by left
                if L <= r + 1:
                    s = word[r - L + 1: r + 1]
                    if s in forb:
                        left = r - L + 2  # exclude this forbidden substring
            ans = max(ans, r - left + 1)

        return ans
