        max_len = 0
        for f in forbidden:
            if len(f) > max_len:
                max_len = len(f)

        # For each forbidden length L, store all forbidden strings of that length
        forb_by_len = defaultdict(set)
        for f in forbidden:
            forb_by_len[len(f)].add(f)

        n = len(word)
        left = 0
        ans = 0

        # Sliding window: maintain that [left..r] is valid
        for r in range(n):
            # If any forbidden substring ends at r, move left accordingly
            for L, sset in forb_by_len.items():
                if L > r - left + 1 or r - L + 1 < left:
                    continue
                start = r - L + 1
                sub = word[start:r + 1]
                if sub in sset:
                    left = start + 1

            ans = max(ans, r - left + 1)

