from typing import List, Dict, Set

class Solution:
    def longestValidSubstring(self, word: str, forbidden: List[str]) -> int:
        # Group forbidden patterns by length for O(K) checks per position
        patterns_by_len: Dict[int, Set[str]] = {}
        max_len = 0
        for s in forbidden:
            L = len(s)
            max_len = max(max_len, L)
            patterns_by_len.setdefault(L, set()).add(s)

        n = len(word)
        left = 0  # invariant: word[left..r] contains no forbidden substring
        best = 0

        # For each position r, check only suffixes of length up to max_len.
        # Any violation must end at r, and its start is r - L + 1.
        for r in range(n):
            new_left = left
            for L, pats in patterns_by_len.items():
                if L > r - left + 1:
                    # even if it matches earlier, it would start before current left,
                    # but only suffix ending at r can be newly introduced by extending to r
                    # Still, safe to check only if L <= r+1, but not needed.
                    pass
                if L <= r + 1:
                    start = r - L + 1
                    if start >= left:
                        # only consider substrings within current window
                        if word[start:r+1] in pats:
                            # move left to one past this occurrence's start
                            # take max if multiple forbidden matches end at r
                            if start + 1 > new_left:
                                new_left = start + 1

            left = new_left
            cur_len = r - left + 1
            if cur_len > best:
                best = cur_len

        return best
