from typing import List
from collections import defaultdict

class Solution:
    def longestValidSubstring(self, word: str, forbidden: List[str]) -> int:
        if not word or not forbidden:
            return len(word)

        # Group forbidden patterns by length for O(K) checks at each position.
        by_len = defaultdict(set)
        max_len = 0
        for f in forbidden:
            by_len[len(f)].add(f)
            if len(f) > max_len:
                max_len = len(f)

        n = len(word)
        left = 0
        ans = 0

        # Sliding window invariant: word[left..r] contains no forbidden substring.
        # When processing r, any new violation must be a forbidden suffix ending at r.
        for r in range(n):
            earliest_start_to_bump = -1  # maximum of (start index) among violating matches

            # Only check substrings ending at r with length up to max_len (<= 10).
            for L, patterns in by_len.items():
                if L > r - left + 1:
                    # Still safe to check, but it cannot be fully inside current window.
                    # We'll just ensure start computed is valid.
                    pass
                start = r - L + 1
                if start < 0:
                    continue
                # If start < left, the substring isn't inside current window yet,
                # but it still would be a substring of the candidate window.
                # We only care about violations inside [left..r], so require start >= left.
                if start < left:
                    continue
                sub = word[start:r+1]
                if sub in patterns:
                    # Window must exclude this forbidden occurrence:
                    # move left to start + 1, so among multiple matches we need max(start)+1.
                    if start > earliest_start_to_bump:
                        earliest_start_to_bump = start

            if earliest_start_to_bump != -1:
                left = earliest_start_to_bump + 1

            ans = max(ans, r - left + 1)

        return ans
